import { createRouter, createWebHashHistory } from 'vue-router'
import HomeView from '../views/HomeView.vue'

const routes = [
  {
    path: '/',
    name: 'home',
    component: HomeView
  },
  {
    path: '/about',
    name: 'about',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "about" */ '../views/AboutView.vue')
  },
  {
    path: '/works',
    name: 'works',
    component: () => import(/* webpackChunkName: "works" */ '../views/WorksView.vue')
  },
  {
    path: '/works/:id',
    name: 'work-detail',
    component: () => import(/* webpackChunkName: "work-detail" */ '../views/WorkDetailView.vue')
  },
  {
    path: '/blogs',
    name: 'blogs',
    component: () => import(/* webpackChunkName: "blogs" */ '../views/BlogsView.vue')
  },
  {
    path: '/misc',
    name: 'misc',
    component: () => import(/* webpackChunkName: "misc" */ '../views/MiscView.vue')
  }
]

const router = createRouter({
  history: createWebHashHistory(),
  routes
})

export default router
